external_knowledge:
- 'Typical age' refers to the average age; 
- 'General age' refers to the overall average age of all sailors;
- 'Members' refers to the sailors associated with the clubs.

sql:
SELECT sailors.name, sailors.club, clubs.location
FROM sailors
INNER JOIN clubs ON sailors.club = clubs.club_name;

SELECT sailors.name, sailors.sail_no, boats.make, boats.model
FROM sailors
INNER JOIN boats ON sailors.sailor_id = boats.owner_id;

SELECT AVG(rating) AS average_rating
FROM sailors
WHERE club = 'HBSC';

SELECT COUNT(sailor_id) 
FROM sailors 
WHERE club = 'Club A';

